/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWCotacaoFrete-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&CotCod.IsEmpty() AND &CotPedCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Sequência") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CotCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Pedido") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = &CotPedCod EndIf If not (&CotDta.IsEmpty() AND &CotDta_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Data") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CotDta WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CotDta_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'COTTRACODRAZ' &CotTraCodRaz1.FromString(&GridStateDynamicFilter.Value) If not &CotTraCodRaz1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Trans." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CotTraCodRaz1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'COTTRACODRAZ' &CotTraCodRaz2.FromString(&GridStateDynamicFilter.Value) If not &CotTraCodRaz2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Trans." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CotTraCodRaz2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'COTTRACODRAZ' &CotTraCodRaz3.FromString(&GridStateDynamicFilter.Value) If not &CotTraCodRaz3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nome Trans." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CotTraCodRaz3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Sequência" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Data/Hora" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Pedido" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Transportadora" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Nro.Cotação" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Valor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "% Ped." &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Escolhida"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod (CotCod) when &OrderedBy = 1 order CotCod when &OrderedBy = 2 AND &OrderedDsc = False order (CotCod) when &OrderedBy = 2 AND &OrderedDsc = True order CotPedCod when &OrderedBy = 3 AND &OrderedDsc = False order (CotPedCod) when &OrderedBy = 3 AND &OrderedDsc = True order CotNro when &OrderedBy = 4 AND &OrderedDsc = False order (CotNro) when &OrderedBy = 4 AND &OrderedDsc = True order CotVlr when &OrderedBy = 5 AND &OrderedDsc = False order (CotVlr) when &OrderedBy = 5 AND &OrderedDsc = True order CotIs when &OrderedBy = 6 AND &OrderedDsc = False order (CotIs) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWCotacaoFrete(&CotCod, &CotPedCod, &DynamicFiltersSelector1, &CotTraCodRaz1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &CotTraCodRaz2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &CotTraCodRaz3, &CotDta, &CotDta_To)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = CotCod &DataHora = trim(DtoC(CotDta)) + ' ' + trim(CotHor) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&DataHora) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = CotPedCod &gridCotTraCodRaz = CotTraCodRaz &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(&GridCotTraCodRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(CotNro) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = CotVlr RetornaTotalLiquidoBruto.Call(EmpCod, CotFilCod, CotPedCod, &PedVlrBrt, &PedVlrLiq)
&Percentual = 0 if &PedVlrLiq > 0 and CotVlr > 0 &Percentual = (CotVlr / &PedVlrLiq) * 100 if &Percentual < 0 &Percentual = 0 EndIF EndIF
&ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Number = &Percentual &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = CotIs.ToString()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCotacaoFreteGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCotacaoFreteGridState")) Else &GridState.FromXml(&Session.Get(!"WWCotacaoFreteGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"COTCOD" &CotCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"COTPEDCOD" &CotPedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"COTDTA" &CotDta.FromString(&GridStateFilterValue.Value) &CotDta_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
